const body = $input.first().json.body || $input.first().json || {};
const apiUrl = $env.N3_API_URL || '{{$env.GATEWAY_URL}}';
const secret = $env.N8N_INTERNAL_SECRET;
if (!secret) return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET未設定', code: 'CONFIG_ERROR' } }];
const productId = body.product_id;
const marketplace = body.marketplace || 'tmall_global';
const shippingModel = body.shipping_model || 'direct';
const bondedWarehouse = body.bonded_warehouse || null;
if (!productId) return [{ json: { error: true, message: 'product_id は必須', code: 'MISSING_PARAM' } }];
return [{ json: { product_id: productId, marketplace: marketplace, shipping_model: shippingModel, bonded_warehouse: bondedWarehouse, api_url: apiUrl } }];

const config = $node['🔐 初期化'].json;
const productRaw = $node['📦 商品情報取得'].json;
const marketplaceRaw = $node['🏪 販路情報取得'].json;
const complianceRaw = $node['📋 規制情報取得'].json;
const settingsRaw = $node['⚙️ 設定取得'].json;

const product = Array.isArray(productRaw) ? productRaw[0] : productRaw;
const marketplace = Array.isArray(marketplaceRaw) ? marketplaceRaw[0] : marketplaceRaw;
const compliance = Array.isArray(complianceRaw) ? complianceRaw[0] : complianceRaw;

if (!product || !product.id) return [{ json: { error: true, message: '商品が見つかりません' } }];
if (!marketplace) return [{ json: { error: true, message: '販路が見つかりません' } }];

// 規制チェック
if (compliance && compliance.is_restricted) {
  return [{ json: { error: true, message: `規制対象商品: ${compliance.restriction_reason}`, code: 'RESTRICTED' } }];
}

// 設定をオブジェクト化
const settings = {};
const settingsArray = Array.isArray(settingsRaw) ? settingsRaw : [settingsRaw];
settingsArray.forEach(s => { if (s && s.setting_key) settings[s.setting_key] = parseFloat(s.setting_value) || s.setting_value; });

// 為替レート
const jpyToCny = 1 / (settings.exchange_rate_cny_jpy || 21);
const usdToCny = settings.exchange_rate_usd_cny || 7.2;

// 価格計算（JPY → CNY）
const purchasePrice = parseFloat(product.purchase_price) || 0;
const purchaseCny = purchasePrice * jpyToCny;

// 越境EC税率（5000CNY以下は9.1%）
const cbecTaxRate = settings.china_cbec_composite_tax || 0.091;
const commissionRate = parseFloat(marketplace.commission_rate) || 0.05;
const paymentFeeRate = parseFloat(marketplace.payment_fee_rate) || 0.02;

// 配送コスト
const shippingCost = config.shipping_model === 'bonded' ? 15 : 30; // CNY

// 原価計算
const totalCost = purchaseCny + shippingCost;
const costWithTax = totalCost * (1 + cbecTaxRate);

// 販売価格（目標利益率20%）
const targetMargin = 0.20;
const salePriceCny = costWithTax / (1 - commissionRate - paymentFeeRate - targetMargin);
const originalPriceCny = salePriceCny * 1.3; // 定価（取り消し線用）

return [{ json: { product_id: product.id, product_title: product.title || product.name, marketplace: config.marketplace, marketplace_name: marketplace.platform_name_cn, shipping_model: config.shipping_model, purchase_price_jpy: purchasePrice, purchase_price_cny: Math.round(purchaseCny * 100) / 100, shipping_cost_cny: shippingCost, cbec_tax_rate: cbecTaxRate, commission_rate: commissionRate, payment_fee_rate: paymentFeeRate, calculated_price_cny: Math.round(salePriceCny * 100) / 100, original_price_cny: Math.round(originalPriceCny * 100) / 100, compliance_status: compliance?.certification_status || 'not_checked', requires_cn_label: compliance?.cn_label_required !== false } }];

const calcResult = $node['💰 価格計算'].json;
const translateResult = $input.first().json;
const titleCn = translateResult.translated || translateResult.text || `【日本直送】${calcResult.product_title}`;
return [{ json: { ...calcResult, title_cn: titleCn } }];

const data = $node['📋 翻訳統合'].json;
const saveResult = $input.first().json;
return [{ json: { success: true, listing_id: saveResult?.id || null, product_id: data.product_id, marketplace: data.marketplace, marketplace_name: data.marketplace_name, title_cn: data.title_cn, price_cny: data.calculated_price_cny, original_price_cny: data.original_price_cny, shipping_model: data.shipping_model, compliance_status: data.compliance_status, requires_cn_label: data.requires_cn_label } }];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
